import React, { useState, useEffect } from "react";
import { useNavigate } from "react-router-dom";
import { useAuth } from "../context/AuthContext";
import toast from "react-hot-toast";
import api from "../services/api";

const EMPTY = {
  title: "",
  category: "Sacred Circuit",
  origin: "Haldwani, Uttarakhand",
  destinations: "",
  duration: "",
  difficulty: "Moderate",
  price: "",
  description: "",
  imageUrl: "",
  highlights: "",
};

const AdminPanel = () => {
  const [tours, setTours] = useState([]);
  const [loading, setLoading] = useState(true);
  const [showForm, setShowForm] = useState(false);
  const [form, setForm] = useState(EMPTY);
  const [saving, setSaving] = useState(false);
  const { isAdmin, logout } = useAuth();
  const navigate = useNavigate();

  useEffect(() => {
    if (!isAdmin) {
      navigate("/admin/login");
      return;
    }
    fetchTours();
  }, [isAdmin]);

  const fetchTours = async () => {
    try {
      const res = await api.get("/admin/tours");
      setTours(res.data.data);
    } catch {
      toast.error("Could not load tours.");
    } finally {
      setLoading(false);
    }
  };

  const handleChange = (e) =>
    setForm((p) => ({ ...p, [e.target.name]: e.target.value }));

  const handleSubmit = async (e) => {
    e.preventDefault();
    setSaving(true);
    try {
      const payload = {
        ...form,
        price: Number(form.price),
        destinations: form.destinations
          .split(",")
          .map((s) => s.trim())
          .filter(Boolean),
        highlights: form.highlights
          .split(",")
          .map((s) => s.trim())
          .filter(Boolean),
      };
      await api.post("/admin/tours", payload);
      toast.success("Tour added!");
      setForm(EMPTY);
      setShowForm(false);
      fetchTours();
    } catch (err) {
      toast.error(err.response?.data?.message || "Failed to save tour.");
    } finally {
      setSaving(false);
    }
  };

  const handleDelete = async (id, title) => {
    if (!window.confirm(`Delete "${title}"?`)) return;
    try {
      await api.delete(`/admin/tours/${id}`);
      setTours((p) => p.filter((t) => t._id !== id));
      toast.success("Tour deleted.");
    } catch {
      toast.error("Delete failed.");
    }
  };

  const handleToggle = async (tour) => {
    try {
      const res = await api.patch(`/admin/tours/${tour._id}`, {
        isActive: !tour.isActive,
      });
      setTours((p) => p.map((t) => (t._id === tour._id ? res.data.data : t)));
    } catch {
      toast.error("Update failed.");
    }
  };

  return (
    <div className="min-h-screen bg-gray-50 pt-20">
      <div className="max-w-6xl mx-auto px-4 py-8">
        {/* Header */}
        <div className="flex items-center justify-between mb-8">
          <div>
            <h1 className="font-display text-3xl font-bold text-gray-900">
              Tour Manager
            </h1>
            <p className="text-gray-500 text-sm mt-1">
              Add, edit or remove trek packages
            </p>
          </div>
          <div className="flex gap-3">
            <button
              onClick={() => setShowForm((v) => !v)}
              className="bg-mountain-900 hover:bg-mountain-700 text-white font-semibold px-5 py-2.5 rounded-xl transition-colors text-sm"
            >
              {showForm ? "Cancel" : "+ Add Tour"}
            </button>
            <button
              onClick={() => {
                logout();
                navigate("/");
              }}
              className="text-sm bg-red-50 hover:bg-red-100 text-red-600 border border-red-200 px-4 py-2.5 rounded-xl transition-colors"
            >
              Logout
            </button>
          </div>
        </div>

        {/* Add Tour Form */}
        {showForm && (
          <form
            onSubmit={handleSubmit}
            className="bg-white rounded-2xl shadow-sm border border-gray-100 p-6 mb-8 space-y-4"
          >
            <h2 className="font-display text-xl font-bold text-gray-900 mb-2">
              New Tour Package
            </h2>
            <div className="grid sm:grid-cols-2 gap-4">
              <div className="sm:col-span-2">
                <label className="label">Title</label>
                <input
                  name="title"
                  value={form.title}
                  onChange={handleChange}
                  required
                  placeholder="Adi Kailash Yatra"
                  className="input"
                />
              </div>
              <div>
                <label className="label">Category</label>
                <select
                  name="category"
                  value={form.category}
                  onChange={handleChange}
                  className="input"
                >
                  <option>Sacred Circuit</option>
                  <option>Alpine Adventure</option>
                </select>
              </div>
              <div>
                <label className="label">Difficulty</label>
                <select
                  name="difficulty"
                  value={form.difficulty}
                  onChange={handleChange}
                  className="input"
                >
                  <option>Easy</option>
                  <option>Moderate</option>
                  <option>Hard</option>
                </select>
              </div>
              <div>
                <label className="label">Duration</label>
                <input
                  name="duration"
                  value={form.duration}
                  onChange={handleChange}
                  required
                  placeholder="8 Days / 7 Nights"
                  className="input"
                />
              </div>
              <div>
                <label className="label">Price (₹ per person)</label>
                <input
                  name="price"
                  value={form.price}
                  onChange={handleChange}
                  required
                  type="number"
                  placeholder="14999"
                  className="input"
                />
              </div>
              <div className="sm:col-span-2">
                <label className="label">Destinations (comma separated)</label>
                <input
                  name="destinations"
                  value={form.destinations}
                  onChange={handleChange}
                  required
                  placeholder="Munsyari, Thamri Kund, Khaliya Top"
                  className="input"
                />
              </div>
              <div className="sm:col-span-2">
                <label className="label">Description</label>
                <textarea
                  name="description"
                  value={form.description}
                  onChange={handleChange}
                  required
                  rows={3}
                  placeholder="Short description of the trek..."
                  className="input resize-none"
                />
              </div>
              <div className="sm:col-span-2">
                <label className="label">Image URL</label>
                <input
                  name="imageUrl"
                  value={form.imageUrl}
                  onChange={handleChange}
                  required
                  placeholder="https://images.unsplash.com/..."
                  className="input"
                />
              </div>
              <div className="sm:col-span-2">
                <label className="label">Highlights (comma separated)</label>
                <input
                  name="highlights"
                  value={form.highlights}
                  onChange={handleChange}
                  placeholder="Sunrise view, Glacial lake, Village homestay"
                  className="input"
                />
              </div>
            </div>
            <button
              type="submit"
              disabled={saving}
              className="bg-mountain-900 hover:bg-mountain-700 disabled:opacity-60 text-white font-semibold px-6 py-3 rounded-xl transition-colors"
            >
              {saving ? "Saving..." : "Save Tour"}
            </button>
          </form>
        )}

        {/* Tours Table */}
        {loading ? (
          <div className="flex justify-center py-20">
            <div className="w-10 h-10 border-4 border-mountain-900/20 border-t-mountain-900 rounded-full animate-spin" />
          </div>
        ) : (
          <div className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden">
            <div className="overflow-x-auto">
              <table className="w-full text-sm">
                <thead>
                  <tr className="bg-gray-50 border-b border-gray-100">
                    {[
                      "Tour",
                      "Category",
                      "Duration",
                      "Price",
                      "Status",
                      "Actions",
                    ].map((h) => (
                      <th
                        key={h}
                        className="text-left px-4 py-3 text-xs font-semibold text-gray-500 uppercase tracking-wider"
                      >
                        {h}
                      </th>
                    ))}
                  </tr>
                </thead>
                <tbody className="divide-y divide-gray-50">
                  {tours.map((t) => (
                    <tr
                      key={t._id}
                      className="hover:bg-gray-50 transition-colors"
                    >
                      <td className="px-4 py-4">
                        <p className="font-medium text-gray-900">{t.title}</p>
                        <p className="text-xs text-gray-400 mt-0.5">
                          {t.difficulty}
                        </p>
                      </td>
                      <td className="px-4 py-4 text-gray-600">{t.category}</td>
                      <td className="px-4 py-4 text-gray-500">{t.duration}</td>
                      <td className="px-4 py-4 font-medium text-mountain-900">
                        ₹{t.price.toLocaleString("en-IN")}
                      </td>
                      <td className="px-4 py-4">
                        <button
                          onClick={() => handleToggle(t)}
                          className={`text-xs font-semibold px-3 py-1.5 rounded-full transition-colors ${
                            t.isActive
                              ? "bg-green-100 text-green-800 hover:bg-green-200"
                              : "bg-gray-100 text-gray-500 hover:bg-gray-200"
                          }`}
                        >
                          {t.isActive ? "Active" : "Hidden"}
                        </button>
                      </td>
                      <td className="px-4 py-4">
                        <button
                          onClick={() => handleDelete(t._id, t.title)}
                          className="text-xs text-red-500 hover:text-red-700 font-medium transition-colors"
                        >
                          Delete
                        </button>
                      </td>
                    </tr>
                  ))}
                  {tours.length === 0 && (
                    <tr>
                      <td
                        colSpan={6}
                        className="text-center py-16 text-gray-400"
                      >
                        No tours yet. Add one above.
                      </td>
                    </tr>
                  )}
                </tbody>
              </table>
            </div>
          </div>
        )}
      </div>

      <style>{`
        .label { display:block; font-size:11px; font-weight:600; color:#6b7280; margin-bottom:6px; text-transform:uppercase; letter-spacing:.05em; }
        .input { width:100%; border:1px solid #e5e7eb; border-radius:12px; padding:10px 14px; font-size:14px; outline:none; transition:border-color .15s; }
        .input:focus { border-color:#1e40af; box-shadow:0 0 0 3px rgba(30,64,175,.1); }
      `}</style>
    </div>
  );
};

export default AdminPanel;
